var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"회동에서 그런 이야기가 오갔군요…… 저는 까맣게 몰랐어요.","JPN":"会合でそんなことがあったんですね……まったく知りませんでした。","ENG":"So that's what happened at the meeting. I had no idea.","TWN":"原來會議上談到了那樣的話題啊……我完全不知道。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그래요. 이제야 기억이 나네요.","JPN":"そうでした。やっと思い出しましたわ。","ENG":"Yes. I remember now.","TWN":"是啊，我現在才想起來。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그 날 이후로 너무 분해서 며칠 동안 식사도 제대로 못 했어요.","JPN":"あの日以来、あまりの悔しさに何日も食事が喉を通りませんでしたわ。","ENG":"I was furious that I could not eat for days.","TWN":"那天之後，我因為太生氣了，好幾天都沒好好吃飯。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"다들 놀랐을 거야. 보통은 학회장직을 승계했다고 공표하는 자리를 예상했거든.","JPN":"みんなびっくりしたはずよ。通常なら学会長職を引き継ぐって公表する場だもの。","ENG":"Everyone might be surprised. They all expected that meeting to be where you declared the position of President.","TWN":"大家應該都嚇到了。因為大部人都猜你會宣佈繼承學會長一職。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"설마 진심으로 정론을 들이밀 거라곤 아무도 예상 못했을걸?","JPN":"まさか本気で正論をつきつけるなんて、誰も予想していなかったわよ。","ENG":"I bet none of them thought that it would be about what the truth is or not.","TWN":"誰也沒想到你會真心地提出正確的主張？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"사람이 음험한 미치광이들 앞에서 공개 망신당한 걸 웃으면서 말하지 말아 주세요.","JPN":"人が公の場で陰険な狂人たちを前に恥をかいたこと、笑いながら話さないでください。","ENG":"Please do not laugh as you discuss my humiliation in front of those crazed lunatics.","TWN":"請不要笑著說出別人在陰險的瘋子面前公開丟臉的事。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럼 결국 망신당한 게 부끄러운 나머지 기억에서 지워 버렸다는 건가?","JPN":"つまり、恥をかいたことが恥ずかしくて記憶から消してしまったということかい？","ENG":"So you buried that memory out of humiliation?","TWN":"那說到底，你是因為太丟臉，覺得不好意思，才在記憶中抹除的嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"크흠, 전 그렇게 치졸한 사람이 아닙니다.","JPN":"コホン、私はそこまで大人げなくはありませんわ。","ENG":"Ahem... I am not that childish of a person.","TWN":"咳咳，我不是那麼幼稚的人。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그런데 신기하네. 학회 사람들은 맥크레디란 이름만 들어도 벌벌 떨던 거 아니었어?","JPN":"でも不思議だね。学会の人たちってマクレディーの名を聞いただけでもビビるんじゃなかったっけ？","ENG":"But it is strange. Don't the Society members all tremble when they hear the name MacCready?","TWN":"不過好神奇啊。學會的人不是應該聽到麥克蕾蒂的名字，就瑟瑟發抖嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"맥크레디라 적당한 선에서 끝난 거야.","JPN":"マクレディーだからその辺で終わったのよ。","ENG":"It was because she is a MacCready that it ended like this.","TWN":"因為是麥克蕾蒂，他們才會適可而止。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"아니면 부학회장님은 지금쯤 어딘가에 갇혀서 차라리 죽여 달라고 애원하고 있을 테니까.","JPN":"そうでなかったら副学会長は今頃どこかに閉じ込められて、いっそのこと殺してくれって哀願してたはずだもの。","ENG":"If it were anyone else, that person would be locked in a cell and begging to be executed.","TWN":"不然的話，副學會長現在就該被關在某個地方，哀求著喊乾脆殺了我吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런데, 콜록……!","JPN":"でも、ゲホッ……！","ENG":"But– *Cough!*","TWN":"可是，咳咳……！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런데 법학부장이란 사람이 한 말은 뭐죠?","JPN":"でも、法学部長という人の話なのですが。","ENG":"But why did that Dean of Law say that to me?","TWN":"可是法學院院長說的話，是什麼意思？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가 학회장 자리에 오르면 다들 따르기라도 한다는 건가요?","JPN":"私が学会長になれば、みんなが従うとでもいうんですの？","ENG":"If I become President, then will they follow me without question?","TWN":"我當上學會長的話，大家就會服從我嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그럼. 학회 내의 누구도 맥크레디 가문 출신의 학회장을 거스르기란 불가능해.","JPN":"もちろんよ。学会内の誰であってもマクレディー家出身の学会長に逆らうことは不可能だわ。","ENG":"Of course. It is impossible for anyone within the Society to disobey a MacCready President.","TWN":"那當然。學會內的任何人都不可能違抗麥克蕾蒂家族出身的學會長。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"절 앞에 세워 놓고 좋을 대로 떠들던 사람들이 말인가요?","JPN":"私を前に自分勝手な主張をしていたあの人たちがですか？","ENG":"Even those who stood in front of me before?","TWN":"也包括那些當著我的面大放厥詞的人嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아니면 설마…… 학회장이 호수를 거느리기 때문에?","JPN":"まさか……学会長が湖を従えているから？","ENG":"Could it be... that it is because the President is in charge of the Lake?","TWN":"或者……難道是因為學會長能支配湖水？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"정답이야, 부학회장님.","JPN":"正解よ、副学会長。","ENG":"Correct, Ms. Vice President!","TWN":"你說對了，副學會長。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"지식의 호수는 많은 것을 담고 있어. 어쩌면 그들이 평생에 걸쳐 갈구하던 해답까지도.","JPN":"知識の湖はたくさんのものを持っているわ。ともすれば彼らが一生求めていた解答までもね。","ENG":"The Lake of Knowledge contains many answers. Some of which are answers to questions they have been searching for all their lives.","TWN":"知識湖水中蘊含著很多東西。或許連他們一生渴求的答案也在那裡。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그리고 학회장은 호수의 파편을 학부에 나눠 줄 수도, 거두어 갈 수도 있지.","JPN":"そして学会長は湖の破片を学部に分けることも、引き取ることもできるの。","ENG":"And the President can grant a Fragment of the Lake or even take it away.","TWN":"而且，學會長既然可以把湖水碎片分給學院，當然也可以收回。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그건 온갖 값진 지식이 담긴 현자의 돌을 자유자재로 다룬다는 뜻이나 마찬가지야.","JPN":"ありとあらゆる価値ある知識が凝縮された賢者の石、それを自由自在に扱うのと同じこと。","ENG":"In other words, you have the power to handle what is the equivalent of the philosopher's stone, which contains all sorts of valuable knowledge.","TWN":"這等於是你可以自由地使用蘊含各種有價值知識的賢者之石。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"특히 맥크레디 가문은 오래 전부터 호수와 상성이 좋았어.","JPN":"特にマクレディー家は昔から湖と相性がよかったのよ。","ENG":"And MacCreadys have long been a good match with the Lake.","TWN":"特別是麥克蕾蒂家族與湖水的克制關係，從很久以前就存在。"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"아마 그들의 피에 흐르는 기질 덕분이었을지도 모르지.","JPN":"たぶん彼らの血に流れる気質のせいじゃないかしらね。","ENG":"Perhaps it has to do with a certain trait in their blood that flows through their veins.","TWN":"或許是因為他們血脈中流淌的氣質的緣故。"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"기질……?","JPN":"気質……？","ENG":"Trait...?","TWN":"氣質……？"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"독기.","JPN":"毒気。","ENG":"Spitefulness.","TWN":"應該說是狠勁。"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"원하는 걸 얻기 위해 한없이 냉철하고, 냉혹해질 수 있는 독기 말이야.","JPN":"ほしいものを手に入れるためには、限りなく冷徹かつ冷酷になれる毒気よ。","ENG":"The callousness and ruthlessness required to obtain whatever one desires.","TWN":"為了得到想要的東西，會變得無比冷靜、無比殘酷的狠勁。"},"stage":{"bg":"ESPR2_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"확실히 워치란 주인과 밀접한 성질을 가지고 있지.","JPN":"確かにウォッチの性質は持ち主と密接な関係がある。","ENG":"Certainly, a Watch and its owner are strongly linked.","TWN":"確實，能量環擁有跟主人密切相關的性格。"},"stage":{"bg":"NANAHARA_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"가문에 대대로 전해진 워치라도, 그 힘을 제대로 발휘하는 건 결국 성질이 유사한 인물뿐이네.","JPN":"家門に代々受け継がれたウォッチでも、その本来の力を発揮させられるのは結局性質が似ている人物だけさ。","ENG":"Even if one is passed on generation after generation, it can only reach its fullest potential when it meets an owner with similar characteristics.","TWN":"即使是家族世代相傳的能量環，真正發揮那種力量的，說到底也只是性格相似的人而已。"},"stage":{"bg":"NANAHARA_04","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"귀염둥이가 한 말대로야.","JPN":"かわい子ちゃんの言うとおりだわ。","ENG":"It's just like cutie-pie said.","TWN":"就像小可愛說的那樣。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그리고 네 어머니의 그 집요한 성정은 죽음을 피할 수단에 향했지.","JPN":"そしてあなたの母親のそのしつこい性根は死を回避する手段へと向かった。","ENG":"And your mother's unyielding rage was aimed at any means of avoiding death.","TWN":"而且，你母親那固執的個性，讓她走上了逃避死亡的路。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"말년에는 정말 닥치는 대로 여기저기 들쑤시고 다녔거든.","JPN":"晩年には本当に手当たり次第にあちこち引っ搔き回していたわ。","ENG":"You see, in her later years, she was desperate for any leads.","TWN":"晚年的時候，她真是一直在到處亂跑。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"죽음을 피할 수단……","JPN":"死を回避する手段……","ENG":"A means of avoiding death...","TWN":"逃避死亡的路……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런 비참한 죽음을 피하고 싶었던 걸까요, 어머니는.","JPN":"惨めな死を避けたかったのでしょうか。母は。","ENG":"Did Mother want to avoid that miserable death?","TWN":"母親，是想逃避那種悲慘的死亡嗎。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그래, 그래. 그 여자, 멘탈 프린팅 기술도 탐냈어.","JPN":"そうそう。あの女、メンタル・プリンティング技術も欲しがってた。","ENG":"Yeah, yeah. I remember she even sought out Mental Printing technology.","TWN":"是的，是的，那個女人，還覬覦智力複印技術。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"셰나가 그런 데 쓰는 게 아니라고 몇 번을 말했는데 듣는 척도 안 하더라.","JPN":"シェナがそんなことに使うものじゃないって何度も言ったけど、聞く耳持たなかったんだよね。","ENG":"Shena told her over and over that it wasn't used for that kind of purpose, but she wouldn't have it.","TWN":"世娜說過很多次智力複印不是用在那種事情的，她都不肯聽。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"이 넓은 수도원을 나 혼자 관리하고 있는 것도 부인 때문이야.","JPN":"この広い修道院を私一人で管理しているのも、夫人のためなの。","ENG":"The reason I am managing the monastery alone is also because of her.","TWN":"我一個人管理這偌大的修道院，也是因為夫人。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"우리 수도원은 원래 신적인 존재를 관측하고 포획하는 데 전념해 왔거든.","JPN":"我が修道院は元々神的な存在を観測して捕獲することに専念してきたわ。","ENG":"We at the monastery devoted ourselves to observing and capturing godlike creatures.","TWN":"因為我們修道院本來就專注於觀測和捕獲神跡。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"우리는 그 그릇을 만들 기술을 완성하기 위해 평생 동안 수도원에서 생활했어.","JPN":"私たちはその器を作る技術を完成させるために一生修道院で暮らしてきた。","ENG":"We vowed to spend our lives at the monastery perfecting the art of creating a vessel for such creatures.","TWN":"為了完成製作那個容器的技術，我們在修道院生活了一輩子。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"이 눈 역시, 작은 성과도 놓치지 않게 주술적으로 개조한 거야.","JPN":"この目も、小さな成果も見逃さないように呪術的に改造したものなの。","ENG":"My right eye's been modified with sorcery to not miss even the tiniest of achievements.","TWN":"這隻眼睛，也是為了不錯過任何微小的成果，才用咒術改造的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런 위험천만한 짓들을 해서 알아내려는 게 호수의 위치라…. 참 한결같군.","JPN":"そのような危なっかしいことをして究めようとしたのが湖の位置か……相変わらずだな。","ENG":"And after going through that dangerous process, all you want is to find out the location of the Lake... How persistent.","TWN":"做那些危險的事情，就只是想要查出湖水的位置……還真是不忘初心啊。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"후훗. 동감이야, 귀염둥이.","JPN":"ふふっ。同感だわ、かわい子ちゃん。","ENG":"Ha ha. I agree cutie-pie.","TWN":"呵呵，我也贊同，小可愛。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"여태 온갖 호칭은 다 들어 봤지만……. 이렇게 어색한 표현은 간만일세.","JPN":"今までいろんな呼び方をされてきたが……これほどしっくりこない表現は久しぶりだな。","ENG":"Of all the nicknames I've had... That is the most awkward one I've heard.","TWN":"至今為止各種稱呼我都聽過了……但是好久沒聽過這麼令人尷尬的稱呼。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"왜? 잘 어울린다고 생각하는데?","JPN":"どうして？　よく似合ってるのに。","ENG":"Hmm? But I think it suits you, no?","TWN":"怎麼了？我感覺很適合你啊？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"아무튼, 그 기술을 응용하면 새로운 몸을 손에 넣을 수 있다고 자신했지만….","JPN":"とにかく、その技術を応用すれば新しい身体を手に入れられると確信したんだけど……","ENG":"Anyway, she was convinced that using that technology would allow her to obtain a new body, but...","TWN":"總之，她堅信應用那個技術後，就能得到新的身體……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"의식 중에 문제가 생긴 데다가 성황청까지 개입해서 완전히 실패하고 말았어.","JPN":"儀式の途中に問題が発生した上に、聖皇庁まで介入してきて完全に失敗してしまったの。","ENG":"It ultimately failed as something went wrong with the ritual, and even Holy Curia intervened.","TWN":"但是儀式進行過程中出了問題，再加上聖皇廳的介入，最後徹底失敗了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"결과는 학회장을 기망한 죄로, 현장에 나가 있던 날 제외하고 본보기로 전원 숙청됐지.","JPN":"結果的に学会長を欺いた罪で、現場に出ていた私を除いて、全員見せしめとして粛清されたわ。","ENG":"As a result, everyone on the scene, except for me who was on the field, was purged to set an example for defrauding the President.","TWN":"結果就是，除了去現場的我之外，剩下的人全都以欺騙學會長的罪名，被當成替罪羊清算了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그런 이야기야.","JPN":"そういうお話。","ENG":"That's my story, anyway.","TWN":"事情就是這樣的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"죄송합니다. 그런 끔찍한 일이 벌어졌는지는 미처 파악 못했어요.","JPN":"すみません。そんな酷いことがあったとも知らずに。","ENG":"I apologize. I had no idea such heinous events had occurred there.","TWN":"對不起，我都不知道發生了那麼可怕的事。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님. 너무 침울해하지 마세요. 부학회장님이 지시하신 것도 아니잖아요.","JPN":"副学会長様。あまりお気を落とさないでください。副学会長様がご指示なさったことでもないんですから。","ENG":"Don't be so glum, ma'am. It wasn't you who ordered the purge...","TWN":"副學會長，你不要太難過了。這些又不是副學會長指使的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"맞아. 부학회장님이 미안해할 것 없어.","JPN":"そうよ。副学会長が悪く思うことはないわ。","ENG":"She's right. There's nothing for you to apologize for.","TWN":"沒錯，副學會長沒什麼好對不起的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"요즘은 새로운 취미도 생겨서 쓸쓸하지 않거든.","JPN":"最近は新しい趣味もできて寂しくないから。","ENG":"Plus, I found a new hobby, so I'm doing well for myself.","TWN":"最近我又有了新愛好，所以一點都不寂寞。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"에그타르트 굽기 맞지? 잔뜩 구워서 햄버거에 끼워 팔면 부자가 될 거야!","JPN":"エッグタルトを焼くことでしょ？　いっぱい焼いてハンバーガーとセットで売ればお金持ちになれるよ！","ENG":"It's making egg tarts, isn't it? If you make a ton and sell them with burgers, you'll be rich in no time!","TWN":"是烤蛋撻對吧？烤得多多的，然後夾在漢堡裡去賣，一定會發大財！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"후훗. 미안하지만 오답이야.","JPN":"ふふっ。残念ながら不正解よ。","ENG":"Ha ha. I'm afraid you are wrong.","TWN":"呵呵，不好意思，回答錯誤。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"무슨 말인지 이해는 했어요. 하지만……","JPN":"どういうことなのかは理解しました。でも……","ENG":"I understand... However...","TWN":"我明白你的意思了，不過……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어머니도 그런 사람이라면 가문의 워치는 왜 하필 제 손에 들어온 거죠?","JPN":"母がそういう人間だったのなら、家門のウォッチはどうしてよりによって私が受け継ぐことになったのでしょうか？","ENG":"If Mother was that kind of person, then why did the Watch come into my hands?","TWN":"如果母親也是那樣的人，家族的能量環為什麼偏偏到了我手裡？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"글쎄. 일반적인 이론만으로는 설명할 수 없는 힘이 작용했을지도 모르지.","JPN":"さあね。一般的な理論だけでは説明できない力が作用したのかのしれないわ。","ENG":"Who knows? Maybe some force that cannot be explained by theory was involved?","TWN":"這個嘛，或許是常規理論無法解釋的力量發揮了作用吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"아니면, 워치에게는 부학회장님이 더 매력적이었다거나?","JPN":"もしくは、ウォッチにとって副学会長がもっと魅力的だったとか？","ENG":"Or, maybe the Watch found you more appealing?","TWN":"再不然，就是對能量環來說副學會長更有魅力？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"시계 취향에 맞춰 주고 싶은 생각은 없습니다만…….","JPN":"ウォッチの好みに合わせるつもりはありませんが……","ENG":"I have no desire to conform to the Watch's preferences, but...","TWN":"我不想迎合一塊手錶的喜好……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"본래는 지식의 호수를 계승하지 않을 방법을 찾고 싶었어요.","JPN":"本来は知識の湖を継承しない方法を見つけたかったのです。","ENG":"I was looking for a way to avoid inheriting the Lake of Knowledge.","TWN":"本來我是想尋找不繼承知識湖水的辦法。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"학회를 정상적인 조직으로 만들면 호수와의 관계도 끊을 수 있을 줄 알았는데….","JPN":"学会を正常な組織にすれば、湖との関係も断つことができると思ったのですが……","ENG":"I believed that if I made the Society into a normal organization that I would be able to cut ties with the Lake...","TWN":"我本來以為只要能把學會變成正常的組織，就能斷絕與湖水的關係……"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"결국 그 둘은 떼어낼 수 없는 관계군요.","JPN":"結局その二つは切っても切れない関係なのですね。","ENG":"But I have learned that the two are inseparable.","TWN":"結果二者卻是密不可分的關係呢。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"정확하게 짚었어.","JPN":"そのとおりよ。","ENG":"Exactly.","TWN":"你說對了。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"부학회장님이 주최했던 회동은 그 점에서 이미 시작부터 실패했다고나 할까?","JPN":"副学会長が主催した会合は、その点で最初から失敗していたというべきかしらね。","ENG":"Shall we say that your plan was doomed to fail from the day you hosted that meeting?","TWN":"從這點來看，副學會長召開的會議可以說從一開始就失敗了。"},"stage":{"bg":"SS_ESPR_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그래서 오늘은 무슨 일이야? 요양하던 호텔에 사고가 났다는 얘기는 들었는데.","JPN":"それで、今日はどうしたのかしら？　療養中のホテルで事故があったとは聞いたけど。","ENG":"Anyway, what brings you here today? I heard there was an accident at the hotel you were recuperating at.","TWN":"所以說，你今天來這裡有什麼事？我聽說你進行休養的飯店裡發生了事故。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"요양이라고 하지만 사실상 감금 생활이었어요.","JPN":"療養と言いますが、実のところは監禁生活でした。","ENG":"It was more being locked away than recuperating.","TWN":"說是休養，其實就是監禁生活。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"담당자라고 있던 이쪽도 사정은 정확히 모르더군요.","JPN":"担当者であったこの人たちも詳しい事情は知りませんの。","ENG":"Even she, who is supposed to be in charge, does not know the exact details either.","TWN":"而且作為負責人的這個人，也不知道具體情況。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"응. 나야 셰나에게 지킬 사람이 필요하단 얘기를 듣고 왔을 뿐이니까.","JPN":"うん。アタシはシェナから監視する人員が必要だってことを聞いてきただけだからね。","ENG":"Hmm? I just heard from Shena that you needed someone to watch over, so I accepted.","TWN":"嗯，我就是聽世娜說需要人守著才來的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그래서 에델을 만날 계획이에요.","JPN":"ですからエデルに会うつもりですの。","ENG":"That is why we are trying to meet with Edel.","TWN":"所以，我打算去見艾瑟兒。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"갑자기 나타났던 괴물은 뭔지, 제가 왜 그런 곳에 갇혀 있었는지.","JPN":"いきなり現れたあの化け物は何なのか、どうして私がそんなところに閉じ込められていたのか。","ENG":"To figure out what that monster was, and why I was locked up there in the first place.","TWN":"突然出現的怪物是什麼，我為什麼被關在那種地方。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……그리고 제가 갇혀 있는 동안 왜 아무 언질도 없었는지.","JPN":"……そして私が閉じ込められている間にどうして何の説明もなかったのか。","ENG":"Also, why I did not hear from her during my time locked up in there.","TWN":"……還有我被關起來的這段時間，她怎麼什麼話都沒說。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"전부 물어 볼 생각이에요.","JPN":"すべて聞いてみるつもりです。","ENG":"I am going to get answers for all of these questions.","TWN":"這些我都想問清楚。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"학부장인 당신이라면 뭔가 알고 있겠죠? 에델은 지금 어디 있죠?","JPN":"学部長であるあなたなら何が知っているはずでは？　エデルは今どこにいますか？","ENG":"As dean, I am confident that you know something? Where she is right now?","TWN":"身為學院院長，你應該知道些什麼吧？艾瑟兒現在在哪裡？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"미안하지만 내 대답은 <color=#ffd34c>아니오</color>야.","JPN":"悪いけど、私の答えは<color=#ffd34c>いいえ</color>だわ。","ENG":"I'm afraid my answer will have to be <color=#ffd34c>no.</color>","TWN":"抱歉，我的答案是<color=#ffd34c>不知道</color>。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"다른 학부장들도 나랑 같지 않을까? 이번 학회장님은 상당히 신출귀몰하시거든.","JPN":"他の学部長も同じじゃないかしら。今度の学会長は相当神出鬼没でいらっしゃるから。","ENG":"I believe the other deans would respond similarly? The current President's whereabouts are at best unexpected.","TWN":"其他學院院長應該也和我一樣吧？因為這屆學會長相當神出鬼沒。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"예를 들어 같은 시간에 다른 곳에서 목격된다거나.","JPN":"例えば同じ時間に多数の場所で目撃されたりとかね。","ENG":"For instance, she could be reported to be seen at multiple places at once.","TWN":"比如可以在同一時間，出現在多個地方。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"영지로 찾아가 보면 어때?","JPN":"領地を訪ねてみるのはどう？","ENG":"But what about heading back to the estate?","TWN":"去領地看看怎麼樣？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"글쎄요. 다른 학회원들이 당신처럼 우호적일 거라는 보장은 없어요.","JPN":"どうでしょう。他の学会員があなたのように友好的である保証はありません。","ENG":"I am not sure. There is no guarantee that the other Society members will be as friendly as you.","TWN":"這個嘛。我不能保證其他學會成員，也會像你一樣友好。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신도 저희가 죽을 위기를 넘겨서야 침식체들을 거두어들였으니까요.","JPN":"あなたも私たちが死の危険を乗り越えた後にやっと侵食体を引かせたでしょう？","ENG":"Then again, you did call off the C.O.s only after we had barely escaped by the skin of our teeth.","TWN":"因為你也是等我們通過生死考驗，才把侵蝕體收回去。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"흐응……. 역시 기본은 하는구나.","JPN":"ふうん……さすがに無知ではないのね。","ENG":"Hmm... So you have thought things through.","TWN":"嗯……你果然很懂啊。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하지만 뾰족한 수가 떠오르지 않아요.","JPN":"でもいい方法が思いつきませんの。","ENG":"But I have not come up with anything brilliant.","TWN":"但是我想不出來好辦法。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이럴 때는 대체 어떻게 해야……","JPN":"こういう時にはいったいどうすれば……","ENG":"What are we supposed to do...?","TWN":"這時候究竟應該怎麼辦……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아비게일 양, 고고학부장의 행적은 알고 있나?","JPN":"アビゲイル君、考古学部長の足取りを知っているかい？","ENG":"Ms. Abigail, do you happen to know where the Dean of Archeology is?","TWN":"亞比該，你知道考古學院院長的行蹤嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"음? 고고학부장과 아는 사이야, 귀염둥이?","JPN":"うん？　考古学部長と知り合いなの？　かわい子ちゃん。","ENG":"Hmm? Do you know the Dean of Archeology, cutie-pie?","TWN":"嗯？你認識考古學院院長，小可愛？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어떤 인물인지 정도는 대강 알고 있지.","JPN":"どんな人物かぐらいは知っている。","ENG":"I know what kind of person he is.","TWN":"我大概知道他是個什麼樣的人。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그렇구나. 확실히 고고학부장이라면 학회장님이 어디 있는지 대답해 줄지도 모르겠네.","JPN":"そうなの。確かに考古学部長なら学会長がどこにいらっしゃるか答えてくれるかもしれないわね。","ENG":"I see. Perhaps he might know where the President is.","TWN":"原來如此。如果是考古學院院長，說不定真能回答學會長在哪裡的問題。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"고고학부장은 회동 때도 참석하지 않았어요. 어떤 사람이죠?","JPN":"考古学部長は会合のときにも参加していませんでしたわ。どんな方ですの？","ENG":"The Dean of Archeology was not present at the meeting. What kind of person is he?","TWN":"考古學院院長在會議時也沒出席，他是個什麼樣的人？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"부학회장님도 이야기는 들어 봤지 않았을까. 학회원들에게는 모범적인 학자상이지.","JPN":"副学会長も話は聞いたことがあるんじゃないかしら。学会員にとっては模範的な学者スタイルよ。","ENG":"I'm sure you've heard of him. He is the academic role model for the majority of the members here.","TWN":"副學會長應該也聽說過吧。對學會成員來說，他是個模範學者。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"물론 부학회장님은 조금 달갑지 않을지도 모르겠지만.","JPN":"もちろん副学会長はあまり好きではないかもしれないけど。","ENG":"But maybe you won't be so delighted to see him.","TWN":"當然，副學會長可能會不太滿意。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"다른 방법을 찾겠다면 말리지 않을게.","JPN":"他の方法を探すなら止めないけど。","ENG":"I won't stop you if you want to find another way.","TWN":"你要是想找別的辦法，我不會攔著你。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"자, 어떻게 할래?","JPN":"どうする？","ENG":"So, what will it be?","TWN":"所以，你的決定是什麼？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};